import React from 'react';
import './about.scss';

export const getWorkYears = (dobStr) => {
  // dobStr in formato "YYYY-MM-DD", es. "2000-10-28"
  const [y, m, d] = dobStr.split('-').map(Number);
  const dob = new Date(y, m - 1, d); // mese 0-based
  const now = new Date();

  let workyears = now.getFullYear() - dob.getFullYear();
  const hadworksyearnumber =
    now.getMonth() > dob.getMonth() ||
    (now.getMonth() === dob.getMonth() && now.getDate() >= dob.getDate());

  if (!hadworksyearnumber) workyears--;
  return workyears;
};

const Info = () => {

  const workyears = getWorkYears('2024-03-11');

  return (
    <div className="about_info grid">
      <div className="about_box">
        <i class='bx bx-award about_icon'></i>

        <h3 className="about_title">Experiences</h3>
        <span className="about_subtitle">workyears</span>
      </div>

      <div className="about_box">
        <i class='bx bx-briefcase-alt about_icon' ></i>

        <h3 className="about_title">Projects</h3>
        <span className="about_subtitle">+10 Completed</span>
      </div>

      <div className="about_box">
        <i class='bx bx-support about_icon'></i>

        <h3 className="about_title">Availability</h3>
        <span className="about_subtitle">Freelance / Remote</span>
      </div>
    </div>
  )
}

export default Info;
